def test_api_timeout_failure_is_retryable(api_integration: ApiIntegration, monkeypatch: pytest.MonkeyPatch) -> None:
    """httpx timeout exceptions are classified as retryable timeout failures."""

    def raise_timeout(*args: Any, **kwargs: Any) -> None:
        raise httpx.ConnectTimeout("timed out")

    monkeypatch.setattr(httpx, "request", raise_timeout)

    binding = {"method": "GET", "url_template": "https://example.test/timeout", "headers": {}}
    result = api_integration.start(binding, {})

    assert result.status == "failed"
    assert result.error_code == "timeout"
    assert result.error_category == "timeout"
    assert result.retryable is True


