def test_api_poll_start_extracts_external_ref(api_integration: ApiIntegration, local_server: str) -> None:
    """Poll mode start returns running with the extracted external ref."""
    binding = {
        "method": "POST",
        "url_template": f"{local_server}/start",
        "completion_mode": "poll",
        "external_ref_path": "job.id",
    }

    result = api_integration.start(binding, {"payload": "ignored"})

    assert result.status == "running"
